import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate, useLocation } from "react-router-dom";

const PaymentScreen = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const order =
    location.state?.order || JSON.parse(localStorage.getItem("orderInfo"));

  const [message, setMessage] = useState("");

  useEffect(() => {
    if (!order) {
      navigate("/products");
    }
  }, [order, navigate]);

  const payHandler = async () => {
    if (!order) {
      alert("No order found");
      return;
    }

    try {
      const { data } = await axios.post(
        "http://localhost:5000/api/payments",
        {
          order: order._id,
          paymentMethod: "COD",
          amount: order.totalAmount,
        }
      );

      setMessage(data.message || "Payment Successful");
    } catch (error) {
      console.log("Payment error:", error.response?.data || error.message);
      alert("Payment failed");
      return;
    }

    try {
      await Promise.all(
        order.items.map((item) =>
          axios.delete(`http://localhost:5000/api/cart/${item.cartItemId}`)
        )
      );
    } catch (err) {
      console.log("Cart delete error:", err.message);
    }

    localStorage.removeItem("orderInfo");
    localStorage.removeItem("selectedCartItems");

    setTimeout(() => {
      navigate("/products");
    }, 2000);
  };

  if (!order) {
    return (
      <div style={{ textAlign: "center", marginTop: "120px" }}>
        <h2>Loading Payment...</h2>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "#f4f6f9",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
      }}
    >
      <div
        style={{
          background: "white",
          padding: "30px",
          borderRadius: "10px",
          width: "350px",
          textAlign: "center",
          boxShadow: "0 0 10px rgba(0,0,0,0.1)",
        }}
      >
        <h2 style={{ marginBottom: "20px" }}>💳 Payment</h2>

        <h3 style={{ marginBottom: "20px" }}>
          Amount: ₹ {order.totalAmount}
        </h3>

        <button
          onClick={payHandler}
          style={{
            padding: "12px 20px",
            background: "green",
            color: "white",
            border: "none",
            borderRadius: "5px",
            fontSize: "16px",
            cursor: "pointer",
            width: "100%",
          }}
        >
          Pay Now
        </button>

        {message && (
          <p
            style={{
              marginTop: "15px",
              color: "green",
              fontWeight: "bold",
            }}
          >
            {message} ✅
          </p>
        )}
      </div>
    </div>
  );
};

export default PaymentScreen;
